/**
 * @param {number[]} nums
 * @return {number}
 */
function solve(nums) {
    // This problem asks for the maximum number of fixed points achievable
    // after deleting any number of elements.
    // A fixed point at index j means the element at index j in the remaining array equals j.
    // Let the remaining elements be the subsequence of the original array nums.
    // If we choose a subsequence at indices i_0, i_1, ..., i_k from the original array
    // such that i_0 < i_1 < ... < i_k, the new array is [nums[i_0], nums[i_1], ..., nums[i_k]].
    // A fixed point exists at new index j (0 <= j <= k) if nums[i_j] == j.
    // We want to maximize the count of j's such that nums[i_j] == j.

    // This is equivalent to finding the Longest Increasing Subsequence (LIS)
    // with a specific constraint, or more simply, a variation of the Longest
    // Common Subsequence problem, which reduces to finding the longest subsequence
    // where the value at the j-th element equals j.

    // Let dp[j] be the maximum number of fixed points we can achieve if the
    // *last* element chosen to be part of the fixed point sequence is nums[j].
    // If nums[j] == j, then nums[j] itself is a fixed point in the original array,
    // but this thinking is flawed because the indices change.

    // Let's rephrase: We are selecting a subsequence of nums, say S.
    // If S has length L, the elements of S are S[0], S[1], ..., S[L-1].
    // We want to maximize count(j | S[j] == j).

    // Consider a greedy approach. We iterate through the original array nums.
    // We want to select elements for our resulting sequence S such that
    // if we select nums[i] as the element at position 'k' in S, we want
    // to maximize the chance that nums[i] == k.

    // Let 'current_target_index' be the next index (0, 1, 2, ...) we are trying
    // to satisfy as a fixed point.
    let fixed_points = 0;

    for (let i = 0; i < nums.length; i++) {
        // If we select nums[i] to be the next element in our resulting subsequence S,
        // its new index will be fixed_points.
        // We achieve a fixed point if nums[i] == fixed_points.
        if (nums[i] === fixed_points) {
            // We greedily choose this element because it satisfies the condition
            // for the current required index (fixed_points), and choosing it
            // allows us to potentially find more fixed points later by increasing
            // the target index for the next element.
            fixed_points++;
        }
        // If nums[i] != fixed_points, we skip nums[i] (i.e., we delete it)
        // because keeping it would place it at index 'fixed_points', and since
        // nums[i] != fixed_points, it wouldn't be a fixed point at this position.
        // Since we want the *maximum* number, and keeping it doesn't help
        // achieve the current target index, deleting it (skipping it) is optimal
        // if we want to maintain the chance to hit the target index 'fixed_points'
        // with a later element, or if we are just building the sequence towards
        // the next fixed point.
        // The crucial insight here is that if nums[i] == fixed_points, we MUST take it
        // if we want to achieve this fixed point count, as any later element
        // nums[j] (j>i) that equals 'fixed_points' would only increase the index
        // of this fixed point candidate, potentially making it not equal to 'fixed_points'.
    }

    return fixed_points;
}

