        // This problem asks for the maximum number of fixed points achievable
        // after deleting any number of elements.
        // A fixed point at new index j means the element at index j in the remaining array equals j.
        // We are looking for the longest subsequence S of nums such that S[j] == j for the maximum number of j's.

        // We can use a greedy approach. We iterate through the original array nums.
        // 'current_target_index' tracks the next index (0, 1, 2, ...) in the resulting subsequence S
        // that we are trying to satisfy as a fixed point.
        long long fixed_points = 0;

        for (size_t i = 0; i < nums.size(); ++i) {
            // If we choose nums[i] to be the next element in our resulting subsequence S,
            // its new index will be 'fixed_points'.
            // We achieve a fixed point if nums[i] == fixed_points.

            if (nums[i] == fixed_points) {
                // Greedily select this element. It contributes to a fixed point
                // at the current target index. We increment the count of fixed points
                // and advance the target index for the next element we select.
