#include <vector>
#include <algorithm>

using namespace std;

long long solve(std::vector<long long> nums) {
    // The problem asks for the maximum number of fixed points achievable after
    // deleting elements, where the remaining elements form a subsequence.
    // If the remaining subsequence is S = [nums[i_0], nums[i_1], ..., nums[i_k]],
    // we want to maximize the count of j such that nums[i_j] == j.

    // This is equivalent to finding the longest subsequence S such that
    // S[j] = j for as many j as possible.
    // A greedy approach works here. We iterate through the original array.
    // We maintain a variable, say 'target_index', which represents the next
    // index (0, 1, 2, ...) in the resulting subsequence that we are trying
    // to make a fixed point for.

    int target_index = 0;

    for (size_t i = 0; i < nums.size(); ++i) {
        // If nums[i] equals the current target_index, we greedily select nums[i]
        // to be the element at position 'target_index' in our resulting subsequence.
        // This achieves a fixed point for this position, and we move on to look 
        // for the next fixed point (i.e., target_index + 1).
        if (nums[i] == target_index) {
            target_index++;
        }
        // If nums[i] != target_index, we skip nums[i] (i.e., delete it).
        // Keeping it would place it at position 'target_index' and it wouldn't
        // be a fixed point, nor would it help us achieve a fixed point at this
        // current target index, which is the most constrained goal.
    }

    // target_index now holds the maximum number of fixed points achieved, 
    // since it was incremented every time a fixed point was successfully formed.
    return target_index;
}

